SELECT
    t_asset_repair.*,
    t_employee.actual_name as applyUserName
FROM t_asset_repair
left join t_employee on t_asset_repair.apply_user_id = t_employee.employee_id



        AND ( INSTR(t_asset_repair.repair_code,#{queryForm.keywords}) or INSTR(t_employee.actual_name,#{queryForm.keywords}) )



        AND t_employee.department_id in

            #{item}




        AND DATE_FORMAT(t_asset_repair.business_date, '%Y-%m-%d') >= #{queryForm.businessDateBegin}


        AND DATE_FORMAT(t_asset_repair.business_date, '%Y-%m-%d') <= #{queryForm.businessDateEnd}


        AND t_asset_repair.enterprise_id = #{queryForm.enterpriseId}


order by t_asset_repair.create_time desc
